content.content:
postgres-auth:
  image: postgres:17-alpine
  container_name: postgres-auth
    POSTGRES_DB: ${AUTH_DB_NAME:-auth_db}
    POSTGRES_USER: ${AUTH_DB_USER:-auth_user}
    POSTGRES_PASSWORD: ${AUTH_DB_PASSWORD}
    - postgres_auth_data:/var/lib/postgresql/data
postgres-core:
  image: postgres:17-alpine
  container_name: postgres-core
    POSTGRES_DB: ${CORE_DB_NAME:-core_db}
    POSTGRES_USER: ${CORE_DB_USER:-core_user}
    POSTGRES_PASSWORD: ${CORE_DB_PASSWORD}
    - postgres_core_data:/var/lib/postgresql/data
  image: redis:7.4-alpine
  container_name: redis
  image: rabbitmq:4.0-management-alpine
  container_name: rabbitmq
  container_name: auth-api
    DATABASE_HOST: postgres-auth

